const DEMO_USER = {
  id: 0,
  username: 'marcus.reynolds',
  email: 'marcus.reynolds@demo.auraalpha.cc',
  display_name: 'Marcus Reynolds',
  tier: 'free',
  onboarding_completed: true,
  account_number: 'U9284761',
  paper_account: 'DU7381052',
  created_at: '2025-11-14T09:22:00Z',
};

export default function LoginPage() {
  usePageTitle('Login');
  const nav = useNavigate();
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [annual, setAnnual] = useState(false);
  const [narrow, setNarrow] = useState(window.innerWidth < 960);

  useEffect(() => {
    const onResize = () => setNarrow(window.innerWidth < 960);
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
  }, []);

  const handleDemo = () => {
    const demoToken = 'demo_' + Date.now();
    localStorage.setItem('aura_token', demoToken);
    localStorage.setItem('aura_user', JSON.stringify(DEMO_USER));
    localStorage.setItem('aura_demo', 'true');
    try { setItem('aura_token', demoToken); setItem('aura_user', JSON.stringify(DEMO_USER)); } catch {}
    nav('/', { replace: true });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const res = await fetch(`${getApiBase()}/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password }),
      });

      const data = await res.json();

      if (!res.ok) {
        setError(data.detail || 'Authentication failed');
        setLoading(false);
        return;
      }

      try {
        localStorage.setItem('aura_token', data.access_token);
        localStorage.setItem('aura_refresh_token', data.refresh_token);
        localStorage.setItem('aura_user', JSON.stringify(data.user));
        // Persist to native Preferences (no-op on web)
        setItem('aura_token', data.access_token);
        setItem('aura_refresh_token', data.refresh_token);
        setItem('aura_user', JSON.stringify(data.user));
      } catch (storageErr) {
        setError('Unable to save session — private browsing mode may not be supported');
        setLoading(false);
        return;
      }

      // Register FCM push token after login (fire-and-forget)
      import('../services/pushNotifications.js').then(({ initPushAndRegister }) => {
        initPushAndRegister().catch(() => {});
      }).catch(() => {});

      // Signal browser credential manager to save password
      if (window.PasswordCredential && navigator.credentials) {
        try {
          const cred = new window.PasswordCredential({
            id: username,
            password: password,
            name: data.user?.display_name || username,
          });
          navigator.credentials.store(cred).catch(() => {});
        } catch (_) { /* Credential API not supported */ }
      }

      if (data.user.onboarding_completed === false) {
        nav('/onboarding', { replace: true });
      } else {
        nav('/', { replace: true });
      }
    } catch (err) {
      setError('Connection failed. Is the API running?');
      setLoading(false);
    }
  };

  const navLinks = [
    { label: 'Features', path: '/features' },
    { label: 'Pricing', path: '/pricing-plans' },
    { label: 'Strategies', path: '/strategies-showcase' },
    { label: 'Docs', path: '/docs' },
  ];

  // -- Pricing Panel (left side) --
  const pricingPanel = (
    <div className={s.pricingPanel}>
      {/* Feature pills */}
      <div className={s.featurePills}>
        {FEATURES.map(f => (
          <span key={f} className={s.featurePill}>{f}</span>
        ))}
      </div>

      {/* Annual toggle */}
      <div className={s.toggleRow}>
        <span className={`${s.toggleLabel} ${annual ? s.toggleLabelInactive : s.toggleLabelActive}`}>Monthly</span>
        <div
          onClick={() => setAnnual(!annual)}
          className={s.toggleTrack}
          style={{ background: annual ? T.green : T.border }}
        >
          <div className={s.toggleKnob} style={{ left: annual ? 23 : 3 }} />
        </div>
        <span className={`${s.toggleLabel} ${annual ? s.toggleLabelActive : s.toggleLabelInactive}`}>Annual</span>
        {annual && <span className={s.saveBadge}>Save up to 35%</span>}
      </div>

      {/* Tier cards */}
      <div className={s.tierGrid}>
        {TIERS.map(tier => (
          <div
            key={tier.name}
            className={s.tierCard}
            style={{ borderColor: tier.badge ? tier.color + '60' : undefined }}
          >
            {tier.badge && (
              <div className={s.tierBadge} style={{ background: tier.color }}>{tier.badge}</div>
            )}
            <div className={s.tierName} style={{ color: tier.color }}>{tier.name}</div>
            <div className={s.tierPriceRow}>
              <div className={s.tierPriceFlex}>
                <span className={s.tierPrice}>${annual ? (tier.annual * 12).toLocaleString() : tier.price}</span>
                <span className={s.tierPeriod}>{annual ? '/yr' : '/mo'}</span>
              </div>
              {annual && (
                <div className={s.tierMonthly}>(${tier.annual}/mo)</div>
              )}
            </div>
            {tier.features.map(f => (
              <div key={f} className={s.tierFeature}>
                <span className={s.tierCheck}>&#10003;</span>
                {f}
              </div>
            ))}
          </div>
        ))}
      </div>

      {/* Free tier callout */}
      <div className={s.freeTier}>
        <span className={s.freeTierHighlight}>Free tier available</span> — Paper
        trading with 1 bot, 10 strategies, US markets only. No credit card required.
      </div>
    </div>
  );

  // -- Login Form Panel (right side on desktop, top on mobile) --
  const formPanel = (
    <div className={s.formPanel}>
      <div className={s.formCard}>
        {/* Header */}
        <div className={s.formHeader}>
          {narrow && <div className={s.narrowLogo}>A</div>}
          <div className={s.formTitle}>Sign In</div>
          <div className={s.formSubtitle}>Access your trading desk</div>
        </div>

        {/* Error */}
        {error && (
          <div className={s.errorBox} role="alert">{typeof error === 'string' ? error : error?.message || 'An error occurred'}</div>
        )}

        {/* Form */}
        <form onSubmit={handleSubmit} name="login" aria-label="Sign in form">
          <label className={s.label} htmlFor="login-username">Username</label>
          <input
            id="login-username"
            type="text"
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            autoFocus
            required
            autoComplete="username"
            name="username"
            placeholder="Enter username"
            aria-required="true"
            className={s.input}
          />

          <label className={s.label} htmlFor="login-password">Password</label>
          <input
            id="login-password"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
            autoComplete="current-password"
            name="password"
            placeholder="Enter password"
            aria-required="true"
            className={s.inputSmallGap}
          />

          <div className={s.forgotRow}>
            <Link to="/forgot-password" className={s.forgotLink}>Forgot password?</Link>
          </div>

          <button
            type="submit"
            disabled={loading}
            aria-busy={loading}
            className={s.submitBtn}
          >
            {loading ? 'Authenticating...' : 'Sign In'}
          </button>
        </form>

        {/* Demo divider + button */}
        <div className={s.divider}>
          <div className={s.dividerLine} />
          <span className={s.dividerText}>or</span>
          <div className={s.dividerLine} />
        </div>
        <button
          type="button"
          onClick={handleDemo}
          className={s.demoBtn}
        >
          Try Free Demo
        </button>
        <div className={s.demoSubtext}>
          Paper trading &bull; No sign-up required
        </div>

        {/* Register link */}
        <div className={s.linkRow}>
          Need an account?{' '}
          <Link to="/register" className={s.blueLink}>
            Create Account
          </Link>
        </div>

        {/* View full pricing link */}
        <div className={s.linkRowSmall}>
          <Link to="/pricing-plans" className={s.purpleLink}>
            View full plan comparison &rarr;
          </Link>
        </div>
      </div>
    </div>
  );

  return (
    <div className={s.page}>
      {/* Gradient orbs */}
      <div className={s.orbBlue} />
      <div className={s.orbPurple} />

      {/* Top nav bar */}
      <div className={s.topNav}>
        <Link to="/" className={s.navLogoLink}>
          <AuraLogo variant="header" height={38} glow />
        </Link>
        {navLinks.map(l => (
          <Link key={l.label} to={l.path + (l.hash || '')} className={s.navLink}>
            {l.label}
          </Link>
        ))}
      </div>

      {/* Full-width top banner with logo */}
      <div className={s.banner}>
        <AuraLogo
          variant="stacked"
          glow
          style={{
            width: '100%',
            maxWidth: narrow ? 360 : 560,
            height: '100%',
            objectFit: 'contain',
            opacity: 0.9,
          }}
        />
        <div className={s.bannerGlow} />
      </div>

      {/* Two-column body */}
      <div className={s.body}>
        {narrow ? (
          <>
            {formPanel}
            {pricingPanel}
          </>
        ) : (
          <>
            {pricingPanel}
            {formPanel}
          </>
        )}
      </div>

      {/* Promotional Section: How Aura Alpha Maximizes Profit */}
      <div className={s.promoSection}>
        <div className={s.promoInner}>
          <div className={s.promoHeaderCenter}>
            <div className={s.promoTitle}>
              How Aura Alpha Maximizes Your Returns
            </div>
            <div className={s.promoDesc}>
              A fully autonomous, multi-layer trading platform that continuously evolves strategies,
              allocates capital intelligently, and manages risk in real-time across global markets.
            </div>
          </div>

          <div className={s.promoGrid}>
            {PROMO_CARDS.map(card => (
              <div key={card.title} className={s.promoCard}>
                <div className={s.promoCardIcon}>{card.icon}</div>
                <div className={s.promoCardTitle}>{card.title}</div>
                <div className={s.promoCardDesc}>{card.desc}</div>
              </div>
            ))}
          </div>

          {/* CTA */}
          <div className={s.ctaCenter}>
            <button onClick={handleDemo} className={s.ctaBtn}>
              Try Free Demo — No Sign-up Required
            </button>
          </div>
        </div>
      </div>

      {/* Compare To Section */}
      <div className={s.compareSection}>
        <div className={s.compareInner}>
          <div className={s.compareTitle}>Compare Aura Alpha To:</div>
          <div className={s.comparePills}>
            {COMPARE_TO.map(name => (
              <Link
                key={name}
                to={`/compare/${name.toLowerCase().replace(/\s+/g, '-')}`}
                className={s.comparePill}
              >
                vs {name}
              </Link>
            ))}
          </div>
        </div>
      </div>

      {/* Footer */}
      <footer className={s.footer}>
        <div className={s.footerInner}>
          {/* Footer link columns */}
          <div className={s.footerGrid}>
            {FOOTER_SECTIONS.map(section => (
              <div key={section.title}>
                <div className={s.footerSectionTitle}>{section.title}</div>
                {section.links.map(link => (
                  <Link key={link.label} to={link.path} className={s.footerLink}>
                    {link.label}
                  </Link>
                ))}
              </div>
            ))}
          </div>

          {/* Divider */}
          <div className={s.footerDivider} />

          {/* Accessibility Statement */}
          <div className={s.accessibilityText}>
            <span className={s.accessibilityLabel}>Accessibility Statement:</span>{' '}
            At Aura Alpha, we're committed to providing accessibility to our website. We're engaged
            in an ongoing process of evaluating our website to ensure a smooth experience for all users.
            If you're having difficulty with your browsing experience, please contact us at{' '}
            <a href="mailto:support@AuraAlpha.cc" className={s.emailLink}>
              support@AuraAlpha.cc
            </a>{' '}
            and we'll happily assist you.
          </div>

          {/* Trading Disclaimer */}
          <div className={s.disclaimerText}>
            <span className={s.disclaimerBold}>Disclaimer:</span>{' '}
            Aura Alpha is a publisher of algorithmic trading tools. No content constitutes a recommendation
            that any particular investment, security, portfolio of securities, transaction or investment
            strategy is suitable for any specific person. All investments involve risk, including possible
            loss of principal. Past performance is not indicative of future results. Please consult with a
            qualified financial advisor before making investment decisions. Trading contains substantial risk
            and is not for every investor. The strategies, tools, and automated systems provided by Aura Alpha
            are for informational and educational purposes. Users are solely responsible for their trading decisions.
          </div>

          {/* Bottom bar */}
          <div className={s.footerBottom}>
            <div className={s.copyright}>
              &copy; {CURRENT_YEAR} Aura Alpha. All rights reserved.
            </div>
            <div className={s.footerBottomLinks}>
              <a href="mailto:support@AuraAlpha.cc" className={s.footerBottomLink}>support@AuraAlpha.cc</a>
              <Link to="/privacy" className={s.footerBottomLink}>Privacy</Link>
              <Link to="/terms" className={s.footerBottomLink}>Terms</Link>
              <Link to="/disclosure" className={s.footerBottomLink}>Disclosure</Link>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
}
